import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class BankTransactionProcessor {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/bank";
    private static final String USER = "root";
    private static final String PASS = "";

    public void processTransaction(int accountNumber, double amount) throws SQLException {
        try (Connection conn = DriverManager.getConnection(DB_URL, USER, PASS)) {
            conn.setAutoCommit(false);

            try (PreparedStatement stmt = conn.prepareStatement("SELECT balance FROM accounts WHERE id = ?")) {
                stmt.setInt(1, accountNumber);
                try (java.sql.ResultSet rs = stmt.executeQuery()) {
                    if (!rs.next()) {
                        System.out.println("Account not found");
                        return;
                    }

                    double currentBalance = rs.getDouble("balance");

                    if (amount <= 0) {
                        System.out.println("Invalid transaction amount");
                        conn.rollback();
                        return;
                    }

                    if (currentBalance < amount) {
                        System.out.println("Insufficient funds");
                        conn.rollback();
                        return;
                    }

                    try (PreparedStatement updateStmt = conn.prepareStatement("UPDATE accounts SET balance = balance - ? WHERE id = ?")) {
                        updateStmt.setDouble(1, amount);
                        updateStmt.setInt(2, accountNumber);
                        updateStmt.executeUpdate();

                        System.out.println("Transaction successful");
                        conn.commit();
                    } catch (SQLException e) {
                        System.out.println("Error updating account balance: " + e.getMessage());
                        conn.rollback();
                    }
                }
            } finally {
                conn.setAutoCommit(true);
            }
        }
    }

    public static void main(String[] args) throws SQLException {
        BankTransactionProcessor processor = new BankTransactionProcessor();
        processor.processTransaction(12345, 100.0);
    }
}